@@ -815,22 +827,33 @@ main {
   transition: color var(--tnz-transition-base);
 }

+.sidebar-content a:not([aria-current="page"]) {
+  color: var(--tnz-nav-link);
+}
+
+.sidebar-content a:not([aria-current="page"]):hover,
+.sidebar-content a:not([aria-current="page"]):focus-visible {
+  color: var(--tnz-nav-link-hover);
+}
+
+/* Override Starlight's large class to match topic navigation size */
+.sidebar-content .large {
+  font-size: var(--tnz-text-sm) !important;
+  font-weight: var(--tnz-font-medium) !important;
+  line-height: var(--tnz-leading-sm) !important;
+}
+
 /* Override Starlight's active page styling - use transparent bg with left border */
 .sidebar-content a[aria-current="page"],
 .sidebar-content a[aria-current="page"]:hover {
   background-color: transparent !important;
   border-inline-start: 2px solid var(--tnz-primary-500) !important;
   padding-inline-start: calc(0.5rem - 2px) !important;
   font-weight: var(--tnz-font-medium) !important;
-  color: var(--sl-color-white) !important;
+  color: var(--tnz-nav-link-active) !important;
   border-radius: 0 !important;
 }

-:root[data-theme="light"] .sidebar-content a[aria-current="page"],
-:root[data-theme="light"] .sidebar-content a[aria-current="page"]:hover {
-  color: var(--tnz-neutral-800) !important;
-}
